module top_module(input CLK_12M,input EVEN,input LOAD,input H,input [31:0] CR,output reg [3:0] GAD, GBD,output reg DOTA, DOTB);reg [31:0] unused_SR; 
  always @(negedge CLK_12M) 
  begin 
  if (LOAD) unused_SR <= CR; 
  else if (H) unused_SR <= {unused_SR[29:24], 2'b00, unused_SR[21:16], 2'b00, unused_SR[13:8], 2'b00, unused_SR[5:0], 2'b00}; 
  else unused_SR <= {2'b00, unused_SR[31:26], 2'b00, unused_SR[23:18], 2'b00, unused_SR[15:10], 2'b00, unused_SR[7:2]}; 
  end 
  always @* 
  begin 
  case ({EVEN, H}) 
  3: {GBD, GAD} <= {unused_SR[31], unused_SR[23], unused_SR[15], unused_SR[7], unused_SR[30], unused_SR[22], unused_SR[14], unused_SR[6]}; 
  2: {GBD, GAD} <= {unused_SR[24], unused_SR[16], unused_SR[8], unused_SR[0], unused_SR[25], unused_SR[17], unused_SR[9], unused_SR[1]}; 
  1: {GBD, GAD} <= {unused_SR[30], unused_SR[22], unused_SR[14], unused_SR[6], unused_SR[31], unused_SR[23], unused_SR[15], unused_SR[7]}; 
  0: {GBD, GAD} <= {unused_SR[25], unused_SR[17], unused_SR[9], unused_SR[1], unused_SR[24], unused_SR[16], unused_SR[8], unused_SR[0]}; 
  endcase 
  {DOTA, DOTB} <= {|GAD, |GBD}; 
  end 
 endmodule
